(x0 : 'a) s1 s2 n:
  nth x0 (s1 ++ s2) n =
    if n < size s1 then nth x0 s1 n else nth x0 s2 (n - size s1)

['a] (x : 'a) (s1 s2 : 'a list) (n : int) :
  insert x (s1 ++ s2) n =
    if n < size s1 then insert x s1 n ++ s2 else s1 ++ insert x s2 (n - size s1)

(m d: int): edivn m d =
  if (d < 0 \/ m < 0) then (0, 0) else
    if d = 0 then (0, m) else choiceb (euclidef m d) (0, 0)
